// Calculate optimal retry time based on failure code and reschedule the attempt.
// Input must include: { id, failure_code }
const attempt = $input.first().json;
const failureCode = attempt.failure_code || '';
const now = new Date();
const dayOfWeek = now.getDay(); // 0=Sun, 6=Sat
const hour = now.getHours();

let delayHours = 4; // default

if (failureCode === 'insufficient_funds') {
  // Retry near payday: 1st or 15th of month
  const today = now.getDate();
  let nextPayday;
  if (today < 15) {
    nextPayday = new Date(now.getFullYear(), now.getMonth(), 15);
  } else {
    nextPayday = new Date(now.getFullYear(), now.getMonth() + 1, 1);
  }
  nextPayday.setHours(10, 0, 0, 0);
  delayHours = Math.max(1, Math.ceil((nextPayday - now) / 3600000));
} else if (failureCode === 'card_declined') {
  delayHours = 24;
} else if (failureCode === 'expired_card') {
  delayHours = 2;
} else {
  // Avoid weekends
  if (dayOfWeek === 5) delayHours = 72;      // Friday → Monday
  else if (dayOfWeek === 6) delayHours = 48; // Saturday → Monday
  else if (hour < 9) delayHours = 9 - hour;
  else if (hour > 20) delayHours = 24 - hour + 9;
}

const scheduledAt = new Date(now.getTime() + delayHours * 3600000).toISOString();

return [{ json: { id: attempt.id, scheduled_at: scheduledAt } }];
